mapper.select:
SELECT DISTINCT FROM t_order o LEFT JOIN t_user u ON o.user_id = u.id LEFT JOIN t_fault_type ft ON o.fault_type_id = ft.id LEFT JOIN t_supplier s ON o.supplier_id = s.id LEFT JOIN t_order_staff os ON o.order_no = os.order_no LEFT JOIN t_staff st ON os.staff_id = st.id WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC
